const item = $input.first().json;

const rawStory = [
  item.submittedStory,
  item.story,
  item.Story,
  item.storyText,
  item['Story'],
]
  .find((value) => typeof value === 'string' && value.trim().length > 0) ?? '';

const submittedStory = String(rawStory).replace(/\r\n/g, '\n').trim();

if (!submittedStory) {
  throw new Error('submittedStory is empty. Check the Form Trigger output key and enter story text before running Input Normalize.');
}

const cleanedStory = submittedStory
  .replace(/\t/g, ' ')
  .replace(/[ \u00A0]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const sceneHeadingCount = (cleanedStory.match(/^#\s*\d+[^\n]*/gm) ?? []).length;
const storyLineCount = cleanedStory.split('\n').filter((line) => line.trim().length > 0).length;

return [{
  json: {
    ...item,
    submittedStory: cleanedStory,
    sceneHeadingCount,
    storyLineCount,
    detectedLanguage: 'ko',
    inputStage: 'input_received',
  },
}];

